insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 0, '地球表面的几何模型中，被称为“重力等位面”的是？', '固体地球表面', '大地水准面', '地球椭球面', '数学曲面', 'B', 'A 错误：固体地球表面是极其复杂的不规则曲面，不是重力等位面。B 正确：大地水准面是一个重力等位面，在理论上与静止海平面重合。C 错误：地球椭球面是一个规则的数学曲面，并不是重力等位面。D 错误：数学模型是为了解决特定测量问题而提出的面，如类地形面等。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 1, '1954年北京坐标系采用的参考椭球是？', 'WGS-84椭球', '1975年国际椭球', '克拉索夫斯基椭球', '海福特椭球', 'C', 'A 错误：WGS-84椭球是1984年创立的，应用于WGS-84坐标系。B 错误：1975年国际椭球被中国1980西安坐标系所采用。C 正确：中国1954年北京坐标系采用的是克拉索夫斯基椭球。D 错误：海福特椭球是中国1953年以前采用的参考椭球。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 2, '确定参考椭球与大地体的位置关系，在大地测量学中称为什么？', '椭球定位', '投影转换', '高程基准', '空间尺度', 'A', 'A 正确：指定一个大地基准面将椭球体与大地体联系起来，称为椭球定位。B 错误：投影转换是指空间数据从一种参考系映射到另一种参考系。C 错误：高程基准是推算水准高程的起算依据。D 错误：空间尺度是研究者选择观察世界的窗口。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 3, '下列坐标系中，起算原点与地球质心重合的是？', '1954年北京坐标系', '1980西安坐标系', '参心空间直角坐标系', '2000国家大地坐标系 (CGCS2000)', 'D', 'A 错误：北京54属于参心坐标系，原点不与地球质心重合。B 错误：西安80也属于参心坐标系，原点设在椭球中心。C 错误：参心坐标系原点位于参考椭球中心，不与质心重合。D 正确：CGCS2000属于地心坐标系统，起算原点和地球质心重合。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 4, '天文地理坐标系是以什么为坐标原点的？', '参考椭球中心', '地心（地球质量中心）', '赤道与中央经线交点', '格林尼治天文台', 'B', 'A 错误：参考椭球中心是参心空间直角坐标系的原点。B 正确：天文地理坐标系以地心为坐标原点。C 错误：赤道与中央经线交点是高斯平面直角坐标系的原点。D 错误：格林尼治天文台用于定义天文首子午面，并非坐标原点。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 5, '为了避免y值出现负值，高斯平面直角坐标系规定各投影带的坐标纵轴应如何平移？', '东移500km', '西移500km', '东移500m', '西移500m', 'B', 'A 错误：东移会使得中央经线以西区域的y值仍然为负。B 正确：规定纵轴均西移500km，使得原横坐标值由0变为500km，以避免负值。C 错误：平移单位是公里(km)，且方向为西移。D 错误：平移单位是公里(km)，不是米(m)。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 6, '若某点位于第19带，横坐标西移前为238765.2m，则其通用横坐标表示为？', '738765.2m', '19238765.2m', '19738765.2m', '19500000m', 'C', 'A 错误：738765.2m是西移后的横坐标，但未加带号无法区分不同投影带。B 错误：该值仅加上了带号，没有加上西移的500000m。C 正确：西移后横坐标为738765.2m，在前面加上带号19，即19738765.2m。D 错误：这是直接用带号拼接500km的错误形式。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 7, '建立地方独立直角坐标系时，地方参考椭球的半径会随什么参数而增大？', '经度差异', '纬度变化', '当地平均海拔高程和高程异常', '中央子午线偏移量', 'C', 'A 错误：地方参考椭球半径变化与经度差异无关。B 错误：参考椭球半径增大与纬度变化无关。C 正确：其椭球半径增大量与当地平均海拔高程及平均高程异常有关。D 错误：中央子午线选取用于投影面确定，不改变椭球半径公式。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 8, '1985国家高程基准面是通过哪个验潮站的资料确定的？', '废黄河验潮站', '坎门验潮站', '大连验潮站', '青岛大港验潮站', 'D', 'A 错误：我国曾使用过废黄河高程基准，但不是1985国家基准。B 错误：坎门高程基准是我国以前使用过的高程基准之一。C 错误：大连高程基准也是以前使用过的基准。D 正确：基准面为青岛大港验潮站1952－1979年资料确定的黄海平均海面。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 9, '在海图中，所谓的“图载水深”指的是哪两面之间的距离？', '深度基准面至海底', '平均海面至海底', '大地水准面至海底', '最高潮面至海底', 'A', 'A 正确：图载水深是该深度基准面至海底的距离。B 错误：平均海面向下一定深度才是深度基准面。C 错误：水深的起算面是深度基准面，而非大地水准面。D 错误：深度基准常位于海面以下较低位置以保证航行安全，与最高潮面无关。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 10, '用符号Vμ表示长度变形，当Vμ<0时，表示？', '投影后长度没有变形', '投影后长度缩小', '投影后长度增加', '投影后长度成倍放大', 'B', 'A 错误：Vμ=0时，投影后长度才没有变形。B 正确：当Vμ<0时，表示投影后长度缩小。C 错误：当Vμ>0时，表示投影后长度增加。D 错误：Vμ<0表示缩小变形，不是放大。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 11, '在投影变形椭圆中，如果长半轴a与短半轴b相等（a=b），则该投影属于？', '等距投影', '等积投影', '等角投影', '任意投影', 'C', 'A 错误：等距离投影的变形椭圆某一半轴与微分圆半径相等（如b=r）。B 错误：等面积投影的变形椭圆特征是a·b=r²。C 正确：如果投影后为大小不同的圆形（a=b），则该投影为等角投影。D 错误：任意投影的面积不等且形状各异。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 12, '按照投影面与地球自转轴的关系，投影面中心轴与地轴相互垂直的投影称为？', '正轴投影', '横轴投影', '斜轴投影', '割投影', 'B', 'A 错误：正轴投影的中心轴与地轴重合。B 正确：横轴投影的投影面中心轴与地轴相互垂直。C 错误：斜轴投影的中心轴与地轴斜交。D 错误：割投影是按投影面与地球表面相割关系划分的。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 13, '高斯—克吕格投影按照构成方法属于哪种投影？', '横轴等角切圆柱投影', '正轴等角切圆柱投影', '正轴等积割圆锥投影', '斜轴等距离方位投影', 'A', 'A 正确：在投影分类中，高斯投影是横轴等角切圆柱投影。B 错误：高斯投影是横轴而非正轴。C 错误：高斯投影使用圆柱面而非圆锥面。D 错误：高斯投影不属于方位投影。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 14, '高斯投影的变形特征之一是，在同一条经线上？', '长度变形随纬度降低而增大，赤道处最大', '长度变形随纬度升高而增大，两极处最大', '长度没有变形', '长度变形恒定不变', 'A', 'A 正确：高斯投影在同一条经线上，长度变形随纬度降低而增大，赤道处最大。B 错误：变形并非在两极处最大。C 错误：除中央经线外，其他经线上均存在变形。D 错误：长度变形随经纬度位置而改变。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 15, '高斯投影6°带的划分标准是？', '自东经1°30''开始，每隔6°为一带', '从0度子午线起，自西向东每隔经差6°为一带', '从西经180°由西向东每隔6°为一带', '从本初子午线起，自东向西每隔6°为一带', 'B', 'A 错误：自东经1°30''开始是3°带的划分标准。B 正确：6°带是从0度子午线起，自西向东每隔经差6°为一投影带。C 错误：这是UTM投影的带号编号起点。D 错误：划分方向应为自西向东。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 16, '通用横轴墨卡托投影（UTM）规定中央经线长度比为多少？', '1.0000', '0.9996', '1.0004', '0.9990', 'B', 'A 错误：中央经线长度比为1是高斯投影的规定。B 正确：UTM投影规定中央经线长度比为0.9996。C 错误：与标准参数不符。D 错误：与标准参数不符。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 17, '我国1:10万比例尺地形图均采用什么投影？', 'UTM投影', '兰勃特投影', '高斯投影', '墨卡托投影', 'C', 'A 错误：我国基本比例尺系统不采用UTM投影。B 错误：兰勃特投影常用于中国全图或分省图。C 正确：我国规定1:10万比例尺地形图等均采用高斯投影。D 错误：墨卡托投影主要用于航线图等。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 18, '在不同地理坐标基准间的转换（如WGS84到西安80）中，用于空间直角坐标基准转换的模型是？', '纯数值多项式拟合', '七参数或简化三参数法', '直接高斯投影正算', '查表插值法', 'B', 'A 错误：多项式拟合适用于无法获取投影信息的单纯数值变换。B 正确：空间直角坐标基准转换利用七参数或三参数法实现参考椭球转换。C 错误：高斯投影公式仅用于大地坐标转平面直角坐标。D 错误：教材并未将查表插值法列为基准转换手段。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 19, '多项式拟合变换属于哪种坐标转换方法？', '投影解析转换', '数值—解析变换', '单纯数值变换', '七参数转换', 'C', 'A 错误：投影解析转换需要存在直接的解析公式。B 错误：数值—解析变换是先数值逼近再代入解析式的方法。C 正确：若无法获取投影信息，可采用多项式拟合这种单纯数值变换法。D 错误：七参数是包含平移、旋转及尺度的三维解析转换。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 20, '遥感仪器所能分辨的最小地面物体大小，称为？', '光谱分辨率', '图像分辨率', '地面像元分辨率', '时间分辨率', 'C', 'A 错误：光谱分辨率是对图像光谱细节分辨能力的度量。B 错误：图像分辨率是成像细节分辨能力的宏观统称。C 正确：地面像元分辨率是遥感仪器所能分辨的最小地面物体大小。D 错误：时间分辨率是序列图像成像的时间间隔。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 21, '数字图像的空间分辨率通过什么指标来严谨表达？', '像元的总数量', '图像文件的大小', '像元的光谱通道数', '离散像元所能分辨的最小尺寸或两点间最小距离', 'D', 'A 错误：像元总数决定幅面而非空间分辨率。B 错误：文件大小与分辨率无绝对等价关系。C 错误：光谱通道与光谱分辨率有关。D 正确：数字图像的空间分辨率应通过离散像元间所能分辨的最小尺寸或最小距离表达。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 22, '在空间尺度分析中，“操作尺度”主要影响的是？', '卫星影像成像时间', '数据处理操作与分析结果的可靠程度', '地图投影变形的计算', '高程基准的确立', 'B', 'A 错误：成像时间概念对应时间分辨率。B 正确：操作尺度是对数据处理时应采用的最佳尺度，影响处理结果可靠度。C 错误：投影变形由数学法则决定，独立于操作尺度。D 错误：高程基准由长期验潮数据推算决定。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 23, '国家标准《地理格网》(GB/T 12409-2009)确立了哪两种并存的格网划分体系？', '高斯格网和UTM格网', '地理坐标格网和直角坐标格网', '像素格网和矢量格网', '行政格网和自然格网', 'B', 'A 错误：虽然有高斯坐标格网，但对应体系是直角坐标体系。B 正确：标准确认了“地理坐标格网”和“直角坐标格网”两种体系并存。C 错误：这是数据模型概念，非标准定位体系。D 错误：行政/自然是区域划分标准，并非此格网划分的数学体系。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 24, '地理坐标格网（经纬格网）体系的优点之一是？', '对应的实地大小非常均匀', '便于进行大区域乃至全球性的拼接', '不会产生任何地图投影变形', '随投影系统的改变而改变位置', 'B', 'A 错误：由于经线收敛，地理坐标格网在实地大小不均匀（高纬度较小）。B 正确：地理坐标格网便于进行大区域乃至全球性的拼接。C 错误：投影到平面必然有变形。D 错误：直角坐标格网才随投影选择改变位置，地理坐标格网不随投影系统改变位置。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-2', 25, '我国基本比例尺地图是以哪种比例尺地形图分幅为基础的？', '1:1万', '1:5万', '1:10万', '1:100万', 'D', 'A、B、C 错误：它们都是基于基础比例尺派生的图幅。D 正确：我国基本比例尺地形图均以1:100万地形图为基础，按经差纬差划分。', datetime('now'));
